"use client";

// PetalFlowLogo.jsx — logo animato PetalFlow, autonomo (nessuna dipendenza esterna).
// Immagini incorporate (petalo + loghi YouTube / X / Meta ricolorati in #8C77EE).
// Uso:  import PetalFlowLogo from "./PetalFlowLogo";
//       <PetalFlowLogo size={120} feedSpeed={6} showWordmark={false} />
// Next.js (App Router): aggiungi  "use client"  in cima SOLO se lo importi in un Server Component.
import React from "react";

const PETAL = "data:image/png;base64,";
const LOGOS = {
  youtube: "data:image/png;base64,",
  x: "data:image/png;base64,",
  meta: "data:image/png;base64,",
};

const CSS = ".pflogo-root *{box-sizing:border-box;}\n@keyframes pflogo-bloom{0%{transform:scale(0) translateY(10px);opacity:0;}55%{opacity:1;}100%{transform:scale(1) translateY(0);opacity:1;}}\n@keyframes pflogo-spin{from{transform:rotate(0deg);}to{transform:rotate(360deg);}}\n@keyframes pflogo-breathe{0%,100%{transform:scale(1);}50%{transform:scale(1.05);}}\n@keyframes pflogo-rise{from{opacity:0;transform:translateY(14px);letter-spacing:.14em;}to{opacity:1;transform:translateY(0);letter-spacing:-.01em;}}\n@keyframes pflogo-glow{0%,100%{opacity:.32;transform:translate(-50%,-50%) scale(.9);}50%{opacity:.58;transform:translate(-50%,-50%) scale(1.18);}}\n@keyframes pflogo-feed{0%{transform:translate3d(0,0,0);}14%{transform:translate3d(0,0,0);animation-timing-function:cubic-bezier(.65,0,.35,1);}33%{transform:translate3d(0,-25%,0);}47%{transform:translate3d(0,-25%,0);animation-timing-function:cubic-bezier(.65,0,.35,1);}66%{transform:translate3d(0,-50%,0);}80%{transform:translate3d(0,-50%,0);animation-timing-function:cubic-bezier(.65,0,.35,1);}100%{transform:translate3d(0,-75%,0);}}\n@keyframes pflogo-float{0%,100%{transform:translate3d(0,0,0) rotate(0deg);}50%{transform:translate3d(0,-7px,0) rotate(-.7deg);}}\n@media (prefers-reduced-motion: reduce){.pflogo-root *{animation:none !important;}}";

const PETALS = [0,45,90,135,180,225,270,315].map((deg, i) => ({
  deg,
  bright: [0.96,1.0,1.04,1.08,1.12,1.08,1.04,1.0][i],
  delay: (0.05 + i*0.09).toFixed(2),
  breathe: [1.2,1.3,1.4,1.5,1.6,1.5,1.4,1.3][i],
}));

// Ordine del flusso nel bocciolo centrale (l'ultimo ripete il primo per loop senza salti)
const FEED = ["youtube","x","meta","youtube"];

export default function PetalFlowLogo({
  size = 140,            // larghezza/altezza del marchio in px
  feedSpeed = 6,         // durata di un ciclo di scorrimento (secondi)
  showWordmark = false,  // mostra il testo "PetalFlow" sotto il marchio
  className = "",
  style = {},
}) {
  const scale = size / 420;            // il marchio è disegnato a 420px e scalato
  const designH = showWordmark ? 540 : 420;

  return (
    <div
      className={"pflogo-root " + className}
      style={{ width: size, height: designH * scale, position: "relative", ...style }}
    >
      <style>{CSS}</style>
      <div
        style={{
          position: "absolute", top: 0, left: 0,
          width: 420, height: designH,
          transform: `scale(${scale})`, transformOrigin: "top left",
          display: "flex", flexDirection: "column", alignItems: "center", gap: 34,
        }}
      >
        {/* ---- FIORE ---- */}
        <div style={{ position: "relative", width: 420, height: 420, display: "flex", alignItems: "center", justifyContent: "center" }}>
          {/* glow viola */}
          <div style={{ position: "absolute", left: "50%", top: "50%", width: 330, height: 330, borderRadius: "50%", background: "radial-gradient(circle, rgba(115,108,242,.28) 0%, rgba(115,108,242,0) 65%)", animation: "pflogo-glow 6s ease-in-out infinite", pointerEvents: "none" }} />

          {/* corona di petali rotante */}
          <div style={{ position: "relative", width: 0, height: 0, animation: "pflogo-spin 40s linear infinite" }}>
            {PETALS.map((p, i) => (
              <div key={i} style={{ position: "absolute", left: 0, top: 0, width: 64, height: 159, marginLeft: -32, marginTop: -159, transformOrigin: "50% 100%", transform: `rotate(${p.deg}deg) translateY(-34px)` }}>
                <img src={PETAL} alt="" draggable={false} style={{ width: "100%", height: "100%", objectFit: "contain", display: "block", transformOrigin: "50% 100%", filter: `brightness(${p.bright})`, animation: `pflogo-bloom .7s cubic-bezier(.34,1.56,.64,1) backwards, pflogo-breathe 5s ease-in-out ${p.breathe}s infinite`, animationDelay: `${p.delay}s` }} />
              </div>
            ))}
          </div>

          {/* bocciolo centrale con feed dei loghi */}
          <div style={{ position: "absolute", left: "50%", top: "50%", width: 80, height: 80, marginLeft: -40, marginTop: -40, zIndex: 6, borderRadius: "50%", filter: "drop-shadow(0 0 16px rgba(140,119,238,.5))", animation: "pflogo-float 7s ease-in-out infinite" }}>
            <div style={{ position: "absolute", inset: 0, borderRadius: "50%", overflow: "hidden", background: "linear-gradient(180deg,#fcfbff 0%,#efeafe 100%)" }}>
              <div style={{ position: "absolute", left: 0, top: 0, width: "100%", height: "400%", animation: `pflogo-feed ${feedSpeed}s infinite`, willChange: "transform", backfaceVisibility: "hidden" }}>
                {FEED.map((name, i) => (
                  <div key={i} style={{ height: "25%", display: "flex", alignItems: "center", justifyContent: "center" }}>
                    <img src={LOGOS[name]} alt={name} draggable={false} style={{ width: name === "x" ? 38 : 44, height: name === "x" ? 38 : 36, objectFit: "contain", display: "block" }} />
                  </div>
                ))}
              </div>
              <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: "28%", background: "linear-gradient(180deg,#fcfbff 0%,rgba(252,251,255,0) 100%)", pointerEvents: "none" }} />
              <div style={{ position: "absolute", bottom: 0, left: 0, right: 0, height: "28%", background: "linear-gradient(0deg,#efeafe 0%,rgba(239,234,254,0) 100%)", pointerEvents: "none" }} />
            </div>
          </div>
        </div>

        {/* ---- WORDMARK opzionale ---- */}
        {showWordmark && (
          <div style={{ fontFamily: "'Manrope', system-ui, sans-serif", fontSize: 62, fontWeight: 800, color: "#1d1d22", letterSpacing: "-.01em", animation: "pflogo-rise .9s cubic-bezier(.22,1,.36,1) .9s backwards" }}>
            PetalFlow
          </div>
        )}
      </div>
    </div>
  );
}
